import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import styled from 'styled-components';
import { FaArrowLeft, FaUsers, FaTasks, FaUserPlus, FaUser } from 'react-icons/fa';

const Container = styled.div`
  min-height: 100vh;
  padding: 20px;
`;

const Header = styled.header`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 30px;
`;

const Title = styled.h1`
  color: white;
`;

const BackBtn = styled(Link)`
  color: white;
  display: flex;
  align-items: center;
  gap: 8px;
  background: rgba(255, 255, 255, 0.2);
  padding: 10px 20px;
  border-radius: 10px;
`;

const Section = styled.section`
  background: white;
  padding: 25px;
  border-radius: 15px;
  margin-bottom: 20px;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.1);
`;

const SectionTitle = styled.h2`
  margin-bottom: 20px;
  display: flex;
  align-items: center;
  gap: 10px;
`;

const MemberList = styled.div`
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
`;

const MemberTag = styled.div`
  background: #f3f4f6;
  padding: 8px 15px;
  border-radius: 20px;
  display: flex;
  align-items: center;
  gap: 8px;
`;

const Modal = styled.div`
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
`;

const ModalContent = styled.div`
  background: white;
  padding: 30px;
  border-radius: 15px;
  width: 90%;
  max-width: 500px;
`;

const Input = styled.input`
  width: 100%;
  padding: 12px;
  margin: 10px 0;
  border: 1px solid #ddd;
  border-radius: 8px;
`;

const Button = styled.button`
  background: #667eea;
  color: white;
  padding: 10px 20px;
  border-radius: 8px;
  margin-right: 10px;
`;

const ProjectDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [project, setProject] = useState(null);
  const [tasks, setTasks] = useState([]);
  const [showAddMember, setShowAddMember] = useState(false);
  const [memberEmail, setMemberEmail] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProjectData();
  }, [id]);

  const fetchProjectData = async () => {
    try {
      const [projectRes, tasksRes] = await Promise.all([
        axios.get(`/api/projects/${id}`),
        axios.get(`/api/projects/${id}/tasks`)
      ]);
      setProject(projectRes.data);
      setTasks(tasksRes.data);
    } catch (error) {
      console.error('Error fetching project:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleAddMember = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`/api/projects/${id}/members`, { email: memberEmail });
      setMemberEmail('');
      setShowAddMember(false);
      fetchProjectData();
    } catch (error) {
      console.error('Error adding member:', error);
      alert(error.response?.data?.message || 'Failed to add member');
    }
  };

  if (loading) return <Container><div style={{ color: 'white' }}>Loading...</div></Container>;
  if (!project) return <Container><div style={{ color: 'white' }}>Project not found</div></Container>;

  return (
    <Container>
      <Header>
        <Title>{project.name}</Title>
        <BackBtn to="/projects">
          <FaArrowLeft /> Back to Projects
        </BackBtn>
      </Header>

      <Section>
        <SectionTitle>
          <FaTasks /> Tasks ({tasks.length})
        </SectionTitle>
        <Link to="/tasks" style={{ color: '#667eea' }}>Manage all tasks →</Link>
      </Section>

      <Section>
        <SectionTitle>
          <FaUsers /> Members ({project.members.length})
        </SectionTitle>
        <MemberList>
          <MemberTag>
            <FaUser /> {project.admin.name} (Admin)
          </MemberTag>
          {project.members.filter(m => m._id !== project.admin._id).map(member => (
            <MemberTag key={member._id}>
              <FaUser /> {member.name}
            </MemberTag>
          ))}
        </MemberList>
        <Button onClick={() => setShowAddMember(true)} style={{ marginTop: '20px' }}>
          <FaUserPlus /> Add Member
        </Button>
      </Section>

      {showAddMember && (
        <Modal onClick={() => setShowAddMember(false)}>
          <ModalContent onClick={e => e.stopPropagation()}>
            <h2>Add Member</h2>
            <form onSubmit={handleAddMember}>
              <Input
                type="email"
                placeholder="Member email"
                value={memberEmail}
                onChange={e => setMemberEmail(e.target.value)}
                required
              />
              <div>
                <Button type="submit">Add</Button>
                <Button type="button" onClick={() => setShowAddMember(false)}>Cancel</Button>
              </div>
            </form>
          </ModalContent>
        </Modal>
      )}
    </Container>
  );
};

export default ProjectDetail;
